// Generate full item list with variants (shiny/golden/rainbow)
function generateItems() {
  const items = [];
  let id = 100000;

  for (const pet of PETS) {
    // Base
    items.push({
      itemid: id++,
      itemname: pet.name,
      itemvalue: pet.value,
      itemimage: API_IMG(pet.name),
      game: "PS99",
    });

    // Only generate variants for Huge and Titanic pets
    if (pet.name.startsWith("Huge ") || pet.name.startsWith("Titanic ")) {
      const baseName = pet.name.replace(/^(Huge |Titanic )/, "");
      const prefix = pet.name.startsWith("Titanic ") ? "Titanic " : "Huge ";

      items.push({
        itemid: id++,
        itemname: `${prefix}Shiny ${baseName}`,
        itemvalue: Math.round(pet.value * 0.6),
        itemimage: API_IMG(`${prefix}Shiny ${baseName}`),
        game: "PS99",
      });
      items.push({
        itemid: id++,
        itemname: `${prefix}Golden ${baseName}`,
        itemvalue: Math.round(pet.value * 0.8),
        itemimage: API_IMG(`${prefix}Golden ${baseName}`),
        game: "PS99",
      });
      items.push({
        itemid: id++,
        itemname: `${prefix}Rainbow ${baseName}`,
        itemvalue: Math.round(pet.value * 1.2),
        itemimage: API_IMG(`${prefix}Rainbow ${baseName}`),
        game: "PS99",
      });
    }
  }

  return items;
}

module.exports = { generateItems };
